query:
UPDATE contacts SET verificationStatus = 'verified', confidenceScore = 'high', emailVerified = true WHERE enrichmentSource = 'linkedin';
UPDATE contacts SET verificationStatus = 'ai_suggested', confidenceScore = 'medium', emailVerified = false WHERE enrichmentSource = 'llm';
UPDATE contacts SET verificationStatus = 'unverified', confidenceScore = 'low', emailVerified = false WHERE enrichmentSource IS NULL OR enrichmentSource = 'manual';
SELECT enrichmentSource, verificationStatus, confidenceScore, COUNT(*) as cnt FROM contacts GROUP BY enrichmentSource, verificationStatus, confidenceScore;

